/*!
 * LDDFWQRCode - minimal pure-JS QR code generator (byte mode, ECC level L, versions 1-10).
 * Bundled with Local Delivery Drivers for WooCommerce. License: MIT.
 *
 * Exposes `window.LDDFWQRCode.toSVG(text, size)` → SVG string.
 *
 * Based on the ISO/IEC 18004 QR specification. Covers only the subset needed
 * for admin-panel URLs (up to ~150 characters at ECC level L, QR version 10).
 * Intentionally avoids automatic mask selection (uses mask 0), automatic ECC
 * level selection (uses L), and other complexity that would bloat the file.
 */
(function (root) {
	'use strict';

	// ---------- Galois field (GF(256)) tables ----------
	var EXP_TABLE = new Array(256);
	var LOG_TABLE = new Array(256);
	(function () {
		for (var i = 0; i < 8; i++) { EXP_TABLE[i] = 1 << i; }
		for (var i = 8; i < 256; i++) {
			EXP_TABLE[i] = EXP_TABLE[i - 4] ^ EXP_TABLE[i - 5] ^ EXP_TABLE[i - 6] ^ EXP_TABLE[i - 8];
		}
		for (var i = 0; i < 255; i++) { LOG_TABLE[EXP_TABLE[i]] = i; }
	})();
	function gexp(n) { while (n < 0) { n += 255; } while (n >= 256) { n -= 255; } return EXP_TABLE[n]; }
	function glog(n) { if (n < 1) { throw new Error('glog(' + n + ')'); } return LOG_TABLE[n]; }

	// ---------- Polynomial helpers ----------
	function Poly(num, shift) {
		var offset = 0;
		while (offset < num.length && num[offset] === 0) { offset++; }
		this.num = new Array(num.length - offset + shift);
		for (var i = 0; i < num.length - offset; i++) { this.num[i] = num[i + offset]; }
	}
	Poly.prototype = {
		get: function (i) { return this.num[i]; },
		len: function () { return this.num.length; },
		multiply: function (e) {
			var num = new Array(this.len() + e.len() - 1);
			for (var i = 0; i < num.length; i++) { num[i] = 0; }
			for (var i = 0; i < this.len(); i++) {
				for (var j = 0; j < e.len(); j++) {
					num[i + j] ^= gexp(glog(this.get(i)) + glog(e.get(j)));
				}
			}
			return new Poly(num, 0);
		},
		mod: function (e) {
			if (this.len() - e.len() < 0) { return this; }
			var ratio = glog(this.get(0)) - glog(e.get(0));
			var num = new Array(this.len());
			for (var i = 0; i < this.len(); i++) { num[i] = this.get(i); }
			for (var i = 0; i < e.len(); i++) { num[i] ^= gexp(glog(e.get(i)) + ratio); }
			return new Poly(num, 0).mod(e);
		}
	};

	// ---------- Version capacity / EC data for level L (versions 1-10) ----------
	// Columns: totalCodewords, ecCodewordsPerBlock, [numBlocks, dataCodewordsPerBlock]*
	var RS_BLOCK_TABLE_L = {
		1:  [ 26,  7, 1,  19],
		2:  [ 44, 10, 1,  34],
		3:  [ 70, 15, 1,  55],
		4:  [100, 20, 1,  80],
		5:  [134, 26, 1, 108],
		6:  [172, 18, 2,  68],
		7:  [196, 20, 2,  78],
		8:  [242, 24, 2,  97],
		9:  [292, 30, 2, 116],
		10: [346, 18, 2,  68, 2, 69]
	};

	// Alignment pattern positions per version (v2+). v1 has none.
	var ALIGN_PATTERN = {
		1: [], 2: [6, 18], 3: [6, 22], 4: [6, 26], 5: [6, 30],
		6: [6, 34], 7: [6, 22, 38], 8: [6, 24, 42], 9: [6, 26, 46], 10: [6, 28, 50]
	};

	function rsBlocks(version) {
		var row = RS_BLOCK_TABLE_L[version];
		var ecc = row[1];
		var blocks = [];
		for (var i = 2; i < row.length; i += 2) {
			for (var j = 0; j < row[i]; j++) {
				blocks.push({ dataCount: row[i + 1], totalCount: row[i + 1] + ecc });
			}
		}
		return blocks;
	}

	// ---------- BitBuffer ----------
	function BitBuffer() { this.buffer = []; this.length = 0; }
	BitBuffer.prototype = {
		get: function (i) { return ((this.buffer[Math.floor(i / 8)] >>> (7 - i % 8)) & 1) === 1; },
		put: function (num, length) { for (var i = 0; i < length; i++) { this.putBit(((num >>> (length - i - 1)) & 1) === 1); } },
		putBit: function (bit) {
			var bufIndex = Math.floor(this.length / 8);
			if (this.buffer.length <= bufIndex) { this.buffer.push(0); }
			if (bit) { this.buffer[bufIndex] |= (0x80 >>> (this.length % 8)); }
			this.length++;
		}
	};

	// ---------- Pick smallest version for data (ECC L) ----------
	function pickVersion(data) {
		// Byte mode length field = 8 bits for v1-9, 16 bits for v10+.
		// Data bits = 4 (mode) + lenBits + 8 * data.length.
		for (var v = 1; v <= 10; v++) {
			var lenBits = v < 10 ? 8 : 16;
			var totalBits = 4 + lenBits + 8 * data.length;
			var dataCap = 0;
			var row = RS_BLOCK_TABLE_L[v];
			for (var i = 2; i < row.length; i += 2) { dataCap += row[i] * row[i + 1]; }
			if (totalBits <= dataCap * 8) { return v; }
		}
		throw new Error('Data too long for LDDFWQRCode (max ~150 chars).');
	}

	// ---------- Encode data ----------
	function encodeData(version, bytes) {
		var buf = new BitBuffer();
		buf.put(4, 4); // byte mode indicator
		var lenBits = version < 10 ? 8 : 16;
		buf.put(bytes.length, lenBits);
		for (var i = 0; i < bytes.length; i++) { buf.put(bytes[i], 8); }

		// Terminator + pad.
		var blocks = rsBlocks(version);
		var totalDataCount = 0;
		for (var i = 0; i < blocks.length; i++) { totalDataCount += blocks[i].dataCount; }
		var totalBits = totalDataCount * 8;
		if (buf.length + 4 <= totalBits) { buf.put(0, 4); }
		while (buf.length % 8 !== 0) { buf.putBit(false); }
		while (buf.length < totalBits) {
			buf.put(0xEC, 8);
			if (buf.length >= totalBits) { break; }
			buf.put(0x11, 8);
		}

		return createDataCodewords(buf, blocks);
	}

	function createDataCodewords(buf, blocks) {
		// Split into blocks + compute RS parity, then interleave.
		var offset = 0;
		var maxDc = 0, maxEc = 0;
		var dcdata = [];
		var ecdata = [];
		for (var r = 0; r < blocks.length; r++) {
			var dcCount = blocks[r].dataCount;
			var ecCount = blocks[r].totalCount - dcCount;
			maxDc = Math.max(maxDc, dcCount);
			maxEc = Math.max(maxEc, ecCount);

			var dc = new Array(dcCount);
			for (var i = 0; i < dcCount; i++) { dc[i] = 0xff & buf.buffer[i + offset]; }
			offset += dcCount;

			var rsPoly = errorCorrectPolynomial(ecCount);
			var rawPoly = new Poly(dc, rsPoly.len() - 1);
			var modPoly = rawPoly.mod(rsPoly);
			var ec = new Array(rsPoly.len() - 1);
			for (var i = 0; i < ec.length; i++) {
				var modIndex = i + modPoly.len() - ec.length;
				ec[i] = modIndex >= 0 ? modPoly.get(modIndex) : 0;
			}
			dcdata.push(dc);
			ecdata.push(ec);
		}

		var totalCodewords = 0;
		for (var i = 0; i < blocks.length; i++) { totalCodewords += blocks[i].totalCount; }
		var data = new Array(totalCodewords);
		var index = 0;
		for (var i = 0; i < maxDc; i++) {
			for (var r = 0; r < blocks.length; r++) {
				if (i < dcdata[r].length) { data[index++] = dcdata[r][i]; }
			}
		}
		for (var i = 0; i < maxEc; i++) {
			for (var r = 0; r < blocks.length; r++) {
				if (i < ecdata[r].length) { data[index++] = ecdata[r][i]; }
			}
		}
		return data;
	}

	function errorCorrectPolynomial(ecLength) {
		var a = new Poly([1], 0);
		for (var i = 0; i < ecLength; i++) { a = a.multiply(new Poly([1, gexp(i)], 0)); }
		return a;
	}

	// ---------- Build matrix ----------
	function sizeForVersion(v) { return v * 4 + 17; }

	function makeMatrix(size) {
		var m = new Array(size);
		for (var i = 0; i < size; i++) {
			m[i] = new Array(size);
			for (var j = 0; j < size; j++) { m[i][j] = null; }
		}
		return m;
	}

	function setFinder(m, row, col) {
		for (var r = -1; r <= 7; r++) {
			if (row + r <= -1 || row + r >= m.length) { continue; }
			for (var c = -1; c <= 7; c++) {
				if (col + c <= -1 || col + c >= m.length) { continue; }
				var isDark = (r >= 0 && r <= 6 && (c === 0 || c === 6)) ||
					(c >= 0 && c <= 6 && (r === 0 || r === 6)) ||
					(r >= 2 && r <= 4 && c >= 2 && c <= 4);
				m[row + r][col + c] = isDark;
			}
		}
	}

	function setTiming(m) {
		for (var i = 8; i < m.length - 8; i++) {
			if (m[i][6] === null) { m[i][6] = (i % 2 === 0); }
			if (m[6][i] === null) { m[6][i] = (i % 2 === 0); }
		}
	}

	function setAlignment(m, version) {
		var positions = ALIGN_PATTERN[version];
		for (var i = 0; i < positions.length; i++) {
			for (var j = 0; j < positions.length; j++) {
				var row = positions[i];
				var col = positions[j];
				if (m[row][col] !== null) { continue; }
				for (var r = -2; r <= 2; r++) {
					for (var c = -2; c <= 2; c++) {
						m[row + r][col + c] = (r === -2 || r === 2 || c === -2 || c === 2 || (r === 0 && c === 0));
					}
				}
			}
		}
	}

	// Format info for ECC level L + mask pattern 0 → precomputed 15-bit value.
	// L=01, mask=000 → raw = 01000 → BCH(15,5) → 111011111000100
	var FORMAT_INFO_L_MASK0 = [1,1,1,0,1,1,1,1,1,0,0,0,1,0,0];

	function setFormatInfo(m) {
		var size = m.length;
		for (var i = 0; i < 15; i++) {
			var mod = FORMAT_INFO_L_MASK0[i] === 1;
			// Vertical (column 8)
			if (i < 6) { m[i][8] = mod; }
			else if (i < 8) { m[i + 1][8] = mod; }
			else { m[size - 15 + i][8] = mod; }
			// Horizontal (row 8)
			if (i < 8) { m[8][size - i - 1] = mod; }
			else if (i < 9) { m[8][15 - i - 1 + 1] = mod; }
			else { m[8][15 - i - 1] = mod; }
		}
		// Always-dark module
		m[size - 8][8] = true;
	}

	function mask0(row, col) { return (row + col) % 2 === 0; }

	function placeData(m, data) {
		var size = m.length;
		var inc = -1;
		var row = size - 1;
		var bitIndex = 7;
		var byteIndex = 0;

		for (var col = size - 1; col > 0; col -= 2) {
			if (col === 6) { col--; }
			while (true) {
				for (var c = 0; c < 2; c++) {
					if (m[row][col - c] === null) {
						var dark = false;
						if (byteIndex < data.length) {
							dark = ((data[byteIndex] >>> bitIndex) & 1) === 1;
						}
						if (mask0(row, col - c)) { dark = !dark; }
						m[row][col - c] = dark;
						bitIndex--;
						if (bitIndex === -1) { byteIndex++; bitIndex = 7; }
					}
				}
				row += inc;
				if (row < 0 || row >= size) { row -= inc; inc = -inc; break; }
			}
		}
	}

	// ---------- Public API ----------
	function generateMatrix(text) {
		var utf8 = unescape(encodeURIComponent(text));
		var bytes = new Array(utf8.length);
		for (var i = 0; i < utf8.length; i++) { bytes[i] = utf8.charCodeAt(i) & 0xff; }

		var version = pickVersion(bytes);
		var size = sizeForVersion(version);
		var m = makeMatrix(size);

		setFinder(m, 0, 0);
		setFinder(m, size - 7, 0);
		setFinder(m, 0, size - 7);
		// Reserve format info areas so data placement skips them.
		for (var i = 0; i < 9; i++) { if (m[i][8] === null) { m[i][8] = false; } if (m[8][i] === null) { m[8][i] = false; } }
		for (var i = size - 8; i < size; i++) { if (m[i][8] === null) { m[i][8] = false; } if (m[8][i] === null) { m[8][i] = false; } }
		setTiming(m);
		setAlignment(m, version);

		var data = encodeData(version, bytes);
		placeData(m, data);
		setFormatInfo(m);

		return { size: size, modules: m };
	}

	function toSVG(text, pixelSize) {
		pixelSize = pixelSize || 180;
		var grid = generateMatrix(text || '');
		var size = grid.size;
		var scale = Math.floor(pixelSize / (size + 4));
		if (scale < 1) { scale = 1; }
		var margin = 2 * scale;
		var total = size * scale + margin * 2;

		var rects = '';
		for (var r = 0; r < size; r++) {
			var runStart = -1;
			for (var c = 0; c < size; c++) {
				var dark = !!grid.modules[r][c];
				if (dark && runStart === -1) { runStart = c; }
				if ((!dark || c === size - 1) && runStart !== -1) {
					var runEnd = dark ? c : c - 1;
					var x = runStart * scale + margin;
					var y = r * scale + margin;
					var w = (runEnd - runStart + 1) * scale;
					rects += '<rect x="' + x + '" y="' + y + '" width="' + w + '" height="' + scale + '"/>';
					runStart = -1;
				}
			}
		}

		return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ' + total + ' ' + total + '" width="' + pixelSize + '" height="' + pixelSize + '">'
			+ '<rect width="100%" height="100%" fill="#fff"/>'
			+ '<g fill="#000">' + rects + '</g>'
			+ '</svg>';
	}

	root.LDDFWQRCode = { toSVG: toSVG };

	// Auto-paint any .lddfw-qr-card__image / [data-lddfw-qr] on DOMContentLoaded.
	function paintAll() {
		var nodes = document.querySelectorAll('[data-lddfw-qr]');
		for (var i = 0; i < nodes.length; i++) {
			var el = nodes[i];
			var url = el.getAttribute('data-lddfw-qr');
			var size = parseInt(el.getAttribute('data-size') || '180', 10);
			try { el.innerHTML = toSVG(url, size); }
			catch (e) { el.textContent = url; }
		}
	}
	if (document.readyState === 'loading') {
		document.addEventListener('DOMContentLoaded', paintAll);
	} else {
		paintAll();
	}
})(typeof window !== 'undefined' ? window : this);
